INSERT INTO position_categories (positionId, name) VALUES (7, 'Analitik Düşünme ve Problem Çözme');
SET @categoryId = LAST_INSERT_ID();
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Gelişmekte olan problemleri görür, önleyici davranış geliştirir.');
