INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Mevcut sorunu gidermek için alternatif çözüm yolları geliştirir.');
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Benzer sorunlar arasında ilişki kurar; geçmişteki deneyimlerden faydalanır.');

INSERT INTO position_categories (positionId, name) VALUES (7, 'Detay Odaklılık');
SET @categoryId = LAST_INSERT_ID();
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'İşlerin hatasız tamamlanması için çaba sarf eder. ');
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Küçük detaylara dikkat eder. ');
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'İşin inceliklerini öğrenmek ve işin bütününe hâkim olabilmek için sürekli gözlem yapar.');
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Hataları, iş çıktıları paylaşılmadan fark eder.');

INSERT INTO position_categories (positionId, name) VALUES (7, 'Duygularını Kontrol Etme ve Yönetme');
SET @categoryId = LAST_INSERT_ID();
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'İş ortamında; kızgınlık, korku, kaygı, üzüntü, depresyon, vb. duygularını kontrol eder. ');
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Özel hayatında yaşadığı sıkıntıları, iş ortamına en az ölçüde yansıtır.');
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Zor çalışma koşullarında ve yoğun mesaide bile başarılı sonuçlar elde edebilir.');

INSERT INTO position_categories (positionId, name) VALUES (7, 'Görev Bilinci');
SET @categoryId = LAST_INSERT_ID();
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Yaptığı işi en iyi şekilde yapar. İş disiplini ve görev bilinci yüksektir.');
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Sorumluluğundaki işleri, şirket kural ve prosedürlerine uygun bir biçimde gerçekleştirir.');
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'İşine, kuruma ve kendisine sunulan kaynaklara zarar verecek hiçbir davranış sergilemez.');
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Ahlaki ve etik değerlere uygun davranır.');

INSERT INTO position_categories (positionId, name) VALUES (7, 'Gıda Güvenliği ve Hijyen');
SET @categoryId = LAST_INSERT_ID();
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Ürünlerin son kullanma tarihine dikkat eder. Zayii olmasına izin vermez. (FIFO-İlk Giren İlk Çıkar)');
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Sebzeleri standartlara uygun şekilde yıkar.');
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Küçük ekipmanların hijyenini standartlara uygun olarak sağlar.');
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Gıda güvenliği ve operasyonel prosedür ve talimatları bilir, bunlara uygun hareket eder.');
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Temizlik kimyasallarını İSG kurallarına uygun şekilde kullanır.');
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Çalışma süresince İSG kurallarına uygun hareket eder.');

INSERT INTO position_categories (positionId, name) VALUES (7, 'Kalite Odaklılık');
SET @categoryId = LAST_INSERT_ID();
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Mevcut düzen ve iş yapma yöntemine uygun çalışır. ');
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Kaliteyi belirlenen standartlara göre uyarlar.');
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Yapılan işin kalitesini sürekli geliştirmek yönünde çalışır.');
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'İş yapma yöntemine ilişkin akış ve prosedürlerdeki yeniliklere adapte olur.');

INSERT INTO position_categories (positionId, name) VALUES (7, 'Sonuç Odaklılık');
SET @categoryId = LAST_INSERT_ID();
