INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Her türlü iletişimde empati kurmaya özen gösterir.');

INSERT INTO position_categories (positionId, name) VALUES (7, 'İstasyon Yönetimi');
SET @categoryId = LAST_INSERT_ID();
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'İstasyonlarda doğru ürün miktarının bulunmasına özen gösterir.');
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Çalıştığı istasyonların temizliğini ve düzenini sağlar.');
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Çalıştığı ekipmanları özenli ve titiz kullanır. Temizliğini yapar.');

INSERT INTO position_categories (positionId, name) VALUES (7, 'İş Disiplini ve Tutum');
SET @categoryId = LAST_INSERT_ID();
INSERT INTO position_questions (categoryId, questionText) VALUES (@categoryId, 'Dış görünüşüne, saçına, sakalına, kişisel hijyenine dikkat eder. Eldiven, bone kullanır.');
